module shift_register(
	input clk,
	input rst_n,
	input shift_in,
	output reg [7:0] shift_out
);

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
		if (!rst_n)
			shift_out <= 8'b00000000;
		else
			shift_out <= {shift_out[6:0], shift_in};
	end

endmodule
